/**
 * Cypress support file — global afterEach hook for screenshots.
 *
 * Rules:
 *  - PASSED  → take a screenshot (so the report always has one for green tests)
 *  - FAILED  → Cypress already takes an automatic screenshot on failure
 *  - SKIPPED → do nothing
 *
 * Import this in your `cypress/support/e2e.js` file:
 * import 'cypress-json-html-reporter/support';
 */
afterEach(function () {
    if (this.currentTest && this.currentTest.state === 'passed') {
        const screenshotName = `${this.currentTest.parent.title} -- ${this.currentTest.title} (passed)`;
        cy.screenshot(screenshotName, { overwrite: true });
    }
});
